#include &lt;stdio.h&gt;

int main() {
    int signed_val = -5;
    unsigned int unsigned_val = 10;

    // DANGER: When comparing signed and unsigned, C implicitly 
    // promotes the signed int to unsigned. -5 becomes 4294967291.
    // Therefore, -5 > 10 evaluates to TRUE.
    if (signed_val > unsigned_val) {
        printf("Mathematics is broken. -5 is greater than 10.\n");
    }
    return 0;
}

