// Safe addition function preventing Undefined Behavior
bool safe_add(int a, int b, int *result) {
    if (a > 0 && b > INT_MAX - a) {
        // Positive overflow would occur
        return false;
    }
    if (a < 0 && b < INT_MIN - a) {
        // Negative underflow would occur
        return false;
    }
    *result = a + b;
    return true;
}

#include &lt;stdio.h&gt;

void char_trap() {
    // The C standard does NOT dictate if 'char' is signed or unsigned.
    // On x86 it defaults to signed, on ARM it often defaults to unsigned.
    char c = 200; 

    // If char is signed, 200 overflows and c equals -56.
    // If char is unsigned, c equals 200.
    // Never use raw 'char' for math. Always specify 'signed char' or 'unsigned char'.
    printf("Value: %d\n", c);
}

