#include &lt;float.h&gt; // Provides FLT_EPSILON

bool is_equal(float a, float b) {
    // NEVER use a == b. 
    // Measure the absolute difference and check if it's smaller than EPSILON.
    if (fabs(a - b) < FLT_EPSILON) {
        return true;
    }
    return false;
}

#include &lt;math.h&gt;
#include &lt;stdio.h&gt;

void check_nan() {
    double result = sqrt(-1.0);

    // NaN poisons all calculations. NaN + 5 = NaN.
    // Bizarrely, IEEE 754 decrees that NaN != NaN.
    if (result == result) {
        printf("Normal number.\n");
    } else {
        // If a variable does not equal itself, it is mathematically NaN.
        // Alternatively, use isnan(result) from <math.h>
        printf("Error: Calculation yielded NaN.\n");
    }
}

#include &lt;stdio.h&gt;
