void run_complex_math() {
    // C99 standardizes complex numbers for electrical engineering/physics
    double complex z1 = 1.0 + 3.0 * I;
    double complex z2 = 1.0 - 4.0 * I;

    double complex sum = z1 + z2;

    // creal extracts the real part, cimag extracts the imaginary part
    printf("Sum: %.1f + %.1fi\n", creal(sum), cimag(sum));
}

