#include &lt;stdio.h&gt;

void const_mechanics() {
    int x = 5;
    int y = 10;

    // 1. Pointer to a const int (The data is locked, pointer can move)
    const int *ptr1 = &x;
    // *ptr1 = 6;  // ERROR: Cannot change the data
    ptr1 = &y;     // OK: Pointer can point to a new address

    // 2. Const pointer to an int (The pointer is locked, data can change)
    int * const ptr2 = &x;
    *ptr2 = 6;     // OK: Can mutate the data
    // ptr2 = &y;  // ERROR: Cannot change the address it points to

    // 3. Const pointer to a const int (Everything is locked)
    const int * const ptr3 = &x;
}

